-- Impacto READ-ONLY da migracao categorias_por_codigo. Apenas SELECTs.
-- Gerado de src/data/categorias-servico.ts; mesma logica da migracao.
WITH codigos(c) AS (VALUES ('1300'),('1310'),('1350'),('1360'),('1380'),('1390'),('1400'),('1410'),('1420'),('1480'),('1490'),('1530'),('1550'),('1555'),('1590'),('2010'),('2011'),('2015'),('2020'),('2030'),('2031'),('2035'),('2040'),('2041'),('2045'),('2050'),('2051'),('2055'),('2060'),('2070'),('2080'),('2090'),('2110'),('2111'),('2120'),('2130'),('2140'),('2145'),('2150'),('2152'),('2160'),('2161'),('2162'),('2170'),('2185'),('2195'),('2530'),('2540'),('2550'),('2560'),('2600'),('2610'),('2620'),('2630'),('2650'),('2660'),('2670'),('2680'),('2690'),('2800'),('2820'),('2830'),('2840'),('2845'),('2860'),('2870'),('3000'),('3010'),('3030'),('3040'),('3060'),('3080'),('3090'),('3110'),('3120'),('3130'),('3150'),('3210'),('3220'),('3240'),('3250'),('3270'),('3500'),('3520'),('3530'),('3540'),('3550'),('3560'),('3570'),('3580'),('3590'),('3600'),('4020'),('4040'),('4041'),('4080'),('4090'),('4100'),('4110'),('4150'),('4530'),('4630'),('5000'),('5010'),('5020'),('5025'),('5040'),('5045'),('5050'),('5060'),('5070'),('5080'),('5090'),('5300'),('5310'),('5320'),('5330'),('5340'),('5350'),('5360'),('5370'),('5380'),('5390'),('5400'),('5410'),('5420'),('5600'),('5610'),('5620'),('5650'),('5690'),('5800'),('5810'),('5830'),('5850'),('5880'),('5900'),('5910'),('5930'),('7070'),('7080'),('7120'),('7305'),('7310'),('7311'),('7330'),('7360'),('7370'),('7380'),('7390'),('7400'),('7420'),('7430'),('7431'),('7450'),('7460'),('7470'),('7480'),('7490'),('7500'),('7510'),('7520'),('7530'),('7540'),('7550'),('7570'),('7580'),('7585'),('7600'),('7610'),('7620'),('7630'),('7640'),('7645'),('7650'),('7660'),('7670'),('7675'),('7680'),('7690'),('7700'),('7705'),('7710'),('7720'),('7730'),('7735'),('7760'),('7765'),('7770'),('7780'),('7790'),('7795'),('7810'),('7820'),('7825'),('7850'),('7851'),('7855')),
fora AS (
  SELECT o.* FROM "OrdemServico" o
  WHERE (o."codigoTss" IS NULL OR o."codigoTss" NOT IN (SELECT c FROM codigos))
    AND (o."codigoTse" IS NULL OR o."codigoTse" NOT IN (SELECT c FROM codigos))
)
SELECT
  (SELECT count(*) FROM "OrdemServico")                              AS total,
  (SELECT count(*) FROM fora)                                        AS seriam_excluidas,
  (SELECT count(*) FROM "OrdemServico") - (SELECT count(*) FROM fora) AS seriam_mantidas,
  (SELECT count(*) FROM fora WHERE "codigoTss" IS NULL AND "codigoTse" IS NULL) AS excluidas_sem_codigo;

-- Top 30 codigos que seriam excluidos (revise se algum deveria estar na tabela):
SELECT COALESCE(NULLIF(TRIM(o."codigoTss"),''), NULLIF(TRIM(o."codigoTse"),''), '(sem codigo)') AS codigo,
       count(*) AS qtd
FROM "OrdemServico" o
WHERE (o."codigoTss" IS NULL OR o."codigoTss" NOT IN (SELECT k FROM (VALUES ('1300'),('1310'),('1350'),('1360'),('1380'),('1390'),('1400'),('1410'),('1420'),('1480'),('1490'),('1530'),('1550'),('1555'),('1590'),('2010'),('2011'),('2015'),('2020'),('2030'),('2031'),('2035'),('2040'),('2041'),('2045'),('2050'),('2051'),('2055'),('2060'),('2070'),('2080'),('2090'),('2110'),('2111'),('2120'),('2130'),('2140'),('2145'),('2150'),('2152'),('2160'),('2161'),('2162'),('2170'),('2185'),('2195'),('2530'),('2540'),('2550'),('2560'),('2600'),('2610'),('2620'),('2630'),('2650'),('2660'),('2670'),('2680'),('2690'),('2800'),('2820'),('2830'),('2840'),('2845'),('2860'),('2870'),('3000'),('3010'),('3030'),('3040'),('3060'),('3080'),('3090'),('3110'),('3120'),('3130'),('3150'),('3210'),('3220'),('3240'),('3250'),('3270'),('3500'),('3520'),('3530'),('3540'),('3550'),('3560'),('3570'),('3580'),('3590'),('3600'),('4020'),('4040'),('4041'),('4080'),('4090'),('4100'),('4110'),('4150'),('4530'),('4630'),('5000'),('5010'),('5020'),('5025'),('5040'),('5045'),('5050'),('5060'),('5070'),('5080'),('5090'),('5300'),('5310'),('5320'),('5330'),('5340'),('5350'),('5360'),('5370'),('5380'),('5390'),('5400'),('5410'),('5420'),('5600'),('5610'),('5620'),('5650'),('5690'),('5800'),('5810'),('5830'),('5850'),('5880'),('5900'),('5910'),('5930'),('7070'),('7080'),('7120'),('7305'),('7310'),('7311'),('7330'),('7360'),('7370'),('7380'),('7390'),('7400'),('7420'),('7430'),('7431'),('7450'),('7460'),('7470'),('7480'),('7490'),('7500'),('7510'),('7520'),('7530'),('7540'),('7550'),('7570'),('7580'),('7585'),('7600'),('7610'),('7620'),('7630'),('7640'),('7645'),('7650'),('7660'),('7670'),('7675'),('7680'),('7690'),('7700'),('7705'),('7710'),('7720'),('7730'),('7735'),('7760'),('7765'),('7770'),('7780'),('7790'),('7795'),('7810'),('7820'),('7825'),('7850'),('7851'),('7855')) AS t(k)))
  AND (o."codigoTse" IS NULL OR o."codigoTse" NOT IN (SELECT k FROM (VALUES ('1300'),('1310'),('1350'),('1360'),('1380'),('1390'),('1400'),('1410'),('1420'),('1480'),('1490'),('1530'),('1550'),('1555'),('1590'),('2010'),('2011'),('2015'),('2020'),('2030'),('2031'),('2035'),('2040'),('2041'),('2045'),('2050'),('2051'),('2055'),('2060'),('2070'),('2080'),('2090'),('2110'),('2111'),('2120'),('2130'),('2140'),('2145'),('2150'),('2152'),('2160'),('2161'),('2162'),('2170'),('2185'),('2195'),('2530'),('2540'),('2550'),('2560'),('2600'),('2610'),('2620'),('2630'),('2650'),('2660'),('2670'),('2680'),('2690'),('2800'),('2820'),('2830'),('2840'),('2845'),('2860'),('2870'),('3000'),('3010'),('3030'),('3040'),('3060'),('3080'),('3090'),('3110'),('3120'),('3130'),('3150'),('3210'),('3220'),('3240'),('3250'),('3270'),('3500'),('3520'),('3530'),('3540'),('3550'),('3560'),('3570'),('3580'),('3590'),('3600'),('4020'),('4040'),('4041'),('4080'),('4090'),('4100'),('4110'),('4150'),('4530'),('4630'),('5000'),('5010'),('5020'),('5025'),('5040'),('5045'),('5050'),('5060'),('5070'),('5080'),('5090'),('5300'),('5310'),('5320'),('5330'),('5340'),('5350'),('5360'),('5370'),('5380'),('5390'),('5400'),('5410'),('5420'),('5600'),('5610'),('5620'),('5650'),('5690'),('5800'),('5810'),('5830'),('5850'),('5880'),('5900'),('5910'),('5930'),('7070'),('7080'),('7120'),('7305'),('7310'),('7311'),('7330'),('7360'),('7370'),('7380'),('7390'),('7400'),('7420'),('7430'),('7431'),('7450'),('7460'),('7470'),('7480'),('7490'),('7500'),('7510'),('7520'),('7530'),('7540'),('7550'),('7570'),('7580'),('7585'),('7600'),('7610'),('7620'),('7630'),('7640'),('7645'),('7650'),('7660'),('7670'),('7675'),('7680'),('7690'),('7700'),('7705'),('7710'),('7720'),('7730'),('7735'),('7760'),('7765'),('7770'),('7780'),('7790'),('7795'),('7810'),('7820'),('7825'),('7850'),('7851'),('7855')) AS t(k)))
